    @for (int i = 0; i < StepLabels.Length; i++)
    {
        var step = i;
        var status = step < _currentStep ? "completed"
                   : step == _currentStep ? "active"
                   : "future";
        <div class="text-center flex-fill step-item @status"
             @onclick="() => GoToStep(step)"
             role="button">
            <div class="step-circle mx-auto mb-1 @status">
                @if (status == "completed")
                {
                    <span>&#10003;</span>
                }
                else
                {
                    <span>@(step + 1)</span>
                }
            </div>
            <small class="d-block">@StepLabels[step]</small>
        </div>
    }
</div>

@if (!string.IsNullOrEmpty(_errorMessage))
{
    <div class="alert alert-danger">@_errorMessage</div>
}

@* ‚îÄ‚îÄ Step Content ‚îÄ‚îÄ *@
@if (_submitted)
{
    <div class="alert alert-success text-center py-5">
        <h4>Application Submitted!</h4>
        <p class="mb-0">Your application ID is <strong>@_applicationId</strong>.</p>
        <p>Thank you for applying. We will be in touch.</p>
    </div>
}
else if (_currentStep == 0)
{
    @* ‚îÄ‚îÄ Step 1: Personal Info ‚îÄ‚îÄ *@
    <div class="card p-4">
        <h5>Personal Information</h5>
        <div class="mb-3">
            <label class="form-label">Full Name <span class="text-danger">*</span></label>
            <input class="form-control" @bind="_fullName" />
        </div>
        <div class="mb-3">
            <label class="form-label">Email <span class="text-danger">*</span></label>
            <input type="email" class="form-control" @bind="_email" />
        </div>
        <div class="mb-3">
            <label class="form-label">Phone <span class="text-danger">*</span></label>
            <input type="tel" class="form-control" @bind="_phone" />
        </div>
        <div class="mb-3">
            <label class="form-label">Address <span class="text-danger">*</span></label>
            <input class="form-control" @bind="_address" />
        </div>
        <div class="d-flex justify-content-end">
            <button class="btn btn-primary" @onclick="NextFromPersonalInfo" disabled="@_loading">
                @if (_loading) { <span class="spinner-border spinner-border-sm me-1"></span> }
                Next
            </button>
        </div>
    </div>
}
else if (_currentStep == 1)
{
    @* ‚îÄ‚îÄ Step 2: Work History ‚îÄ‚îÄ *@
    <div class="card p-4">
        <h5>Work History</h5>
        @for (int i = 0; i < _workEntries.Count; i++)
        {
            var idx = i;
            <div class="border rounded p-3 mb-3 position-relative">
                @if (_workEntries.Count > 1)
                {
                    <button class="btn btn-sm btn-outline-danger position-absolute top-0 end-0 m-2"
                            @onclick="() => RemoveWorkEntry(idx)">Remove</button>
                }
                <div class="row mb-2">
                    <div class="col-md-6">
                        <label class="form-label">Company <span class="text-danger">*</span></label>
                        <input class="form-control" @bind="_workEntries[idx].Company" />
                    </div>
                    <div class="col-md-6">
                        <label class="form-label">Job Title <span class="text-danger">*</span></label>
                        <input class="form-control" @bind="_workEntries[idx].Title" />
                    </div>
                </div>
                <div class="row mb-2">
                    <div class="col-md-4">
                        <label class="form-label">Start Date <span class="text-danger">*</span></label>
                        <input type="date" class="form-control" @bind="_workEntries[idx].StartDate" />
                    </div>
                    <div class="col-md-4">
                        <label class="form-label">End Date</label>
                        <input type="date" class="form-control" @bind="_workEntries[idx].EndDate"
                               disabled="@_workEntries[idx].IsCurrent" />
                    </div>
                    <div class="col-md-4 d-flex align-items-end mb-1">
                        <div class="form-check">
                            <input type="checkbox" class="form-check-input" id="current-@idx"
                                   @bind="_workEntries[idx].IsCurrent" />
                            <label class="form-check-label" for="current-@idx">Currently working here</label>
                        </div>
                    </div>
                </div>
                <div class="mb-2">
                    <label class="form-label">Description</label>
                    <textarea class="form-control" rows="2" @bind="_workEntries[idx].Description"></textarea>
                </div>
            </div>
        }
        <button class="btn btn-outline-secondary mb-3" @onclick="AddWorkEntry">+ Add Another Position</button>
        <div class="d-flex justify-content-between">
            <button class="btn btn-secondary" @onclick="Back">Back</button>
            <button class="btn btn-primary" @onclick="NextFromWorkHistory">Next</button>
        </div>
    </div>
}
else if (_currentStep == 2)
{
    @* ‚îÄ‚îÄ Step 3: References ‚îÄ‚îÄ *@
    <div class="card p-4">
        <h5>References</h5>
        @for (int i = 0; i < _references.Count; i++)
        {
            var idx = i;
            <div class="border rounded p-3 mb-3 position-relative">
                @if (_references.Count > 2)
                {
                    <button class="btn btn-sm btn-outline-danger position-absolute top-0 end-0 m-2"
                            @onclick="() => RemoveReference(idx)">Remove</button>
                }
                <div class="row mb-2">
                    <div class="col-md-6">
                        <label class="form-label">Name <span class="text-danger">*</span></label>
                        <input class="form-control" @bind="_references[idx].Name" />
                    </div>
                    <div class="col-md-6">
                        <label class="form-label">Relationship <span class="text-danger">*</span></label>
                        <input class="form-control" @bind="_references[idx].Relationship" />
                    </div>
                </div>
                <div class="row mb-2">
                    <div class="col-md-6">
                        <label class="form-label">Email <span class="text-danger">*</span></label>
                        <input type="email" class="form-control" @bind="_references[idx].Email" />
                    </div>
                    <div class="col-md-6">
                        <label class="form-label">Phone <span class="text-danger">*</span></label>
                        <input type="tel" class="form-control" @bind="_references[idx].Phone" />
                    </div>
                </div>
            </div>
        }
        @if (_references.Count < 3)
        {
            <button class="btn btn-outline-secondary mb-3" @onclick="AddReference">+ Add Reference</button>
        }
        <div class="d-flex justify-content-between">
            <button class="btn btn-secondary" @onclick="Back">Back</button>
            <button class="btn btn-primary" @onclick="NextFromReferences">Next</button>
        </div>
    </div>
}
else if (_currentStep == 3)
{
    @* ‚îÄ‚îÄ Step 4: Cover Letter ‚îÄ‚îÄ *@
    <div class="card p-4">
        <h5>Cover Letter</h5>
        <div class="mb-2">
            <textarea class="form-control" rows="10" maxlength="2000"
                      @bind="_coverLetter" @bind:event="oninput"></textarea>
        </div>
        <div class="text-muted mb-3">@(_coverLetter?.Length ?? 0) / 2000 characters</div>
        <div class="d-flex justify-content-between">
            <button class="btn btn-secondary" @onclick="Back">Back</button>
            <button class="btn btn-primary" @onclick="NextFromCoverLetter">Next</button>
        </div>
    </div>
}
else if (_currentStep == 4)
{
    @* ‚îÄ‚îÄ Step 5: Review & Submit ‚îÄ‚îÄ *@
    <div class="card p-4">
        <h5>Review Your Application</h5>

        <div class="border rounded p-3 mb-3">
            <div class="d-flex justify-content-between align-items-center mb-2">
                <h6 class="mb-0">Personal Information</h6>
                <a href="javascript:void(0)" @onclick='() => GoToStep(0)'>Edit</a>
            </div>
            <p class="mb-1"><strong>Name:</strong> @_fullName</p>
            <p class="mb-1"><strong>Email:</strong> @_email</p>
            <p class="mb-1"><strong>Phone:</strong> @_phone</p>
            <p class="mb-0"><strong>Address:</strong> @_address</p>
        </div>

        <div class="border rounded p-3 mb-3">
            <div class="d-flex justify-content-between align-items-center mb-2">
                <h6 class="mb-0">Work History</h6>
                <a href="javascript:void(0)" @onclick='() => GoToStep(1)'>Edit</a>
            </div>
            @foreach (var entry in _workEntries)
            {
                <div class="mb-2">
                    <p class="mb-1"><strong>@entry.Title</strong> at @entry.Company</p>
                    <p class="mb-1 text-muted">
                        @entry.StartDate.ToString("MMM yyyy") &ndash;
                        @(entry.IsCurrent ? "Present" : entry.EndDate?.ToString("MMM yyyy"))
                    </p>
                    @if (!string.IsNullOrWhiteSpace(entry.Description))
                    {
                        <p class="mb-0">@entry.Description</p>
                    }
                </div>
            }
        </div>

        <div class="border rounded p-3 mb-3">
            <div class="d-flex justify-content-between align-items-center mb-2">
                <h6 class="mb-0">References</h6>
                <a href="javascript:void(0)" @onclick='() => GoToStep(2)'>Edit</a>
            </div>
            @foreach (var r in _references)
            {
                <p class="mb-1">
                    <strong>@r.Name</strong> (@r.Relationship) &mdash; @r.Email, @r.Phone
                </p>
            }
        </div>

        <div class="border rounded p-3 mb-3">
            <div class="d-flex justify-content-between align-items-center mb-2">
                <h6 class="mb-0">Cover Letter</h6>
                <a href="javascript:void(0)" @onclick='() => GoToStep(3)'>Edit</a>
            </div>
            <p class="mb-0" style="white-space: pre-wrap;">@_coverLetter</p>
        </div>

        <div class="d-flex justify-content-between">
            <button class="btn btn-secondary" @onclick="Back">Back</button>
            <button class="btn btn-success" @onclick="SubmitApplication" disabled="@_loading">
                @if (_loading) { <span class="spinner-border spinner-border-sm me-1"></span> }
                Submit Application
            </button>
        </div>
    </div>
}

@code {
    private static readonly string[] StepLabels =
        ["Personal Info", "Work History", "References", "Cover Letter", "Review & Submit"];

    private int _currentStep;
    private bool _loading;
    private bool _submitted;
    private int _applicationId;
    private string? _errorMessage;

    // Step 1
    private string _fullName = "";
    private string _email = "";
    private string _phone = "";
    private string _address = "";

    // Step 2
    private List<WorkEntryModel> _workEntries = [new()];

    // Step 3
    private List<ReferenceModel> _references = [new(), new()];

    // Step 4
    private string _coverLetter = "";

    private void GoToStep(int step)
    {
        if (step < _currentStep)
        {
            _errorMessage = null;
            _currentStep = step;
        }
    }

    private void Back()
    {
        _errorMessage = null;
        if (_currentStep > 0) _currentStep--;
    }

    private async Task NextFromPersonalInfo()
    {
        _errorMessage = null;
        if (string.IsNullOrWhiteSpace(_fullName) || string.IsNullOrWhiteSpace(_email)
            || string.IsNullOrWhiteSpace(_phone) || string.IsNullOrWhiteSpace(_address))
        {
            _errorMessage = "All personal info fields are required.";
            return;
        }

        _loading = true;
        try
        {
            var valid = await ApplicationService.ValidateEmailAsync(_email);
            if (!valid)
            {
                _errorMessage = "Please enter a valid email address.";
                return;
            }
            _currentStep = 1;
        }
        finally { _loading = false; }
    }

    private void NextFromWorkHistory()
    {
        _errorMessage = null;
        foreach (var e in _workEntries)
        {
            if (string.IsNullOrWhiteSpace(e.Company) || string.IsNullOrWhiteSpace(e.Title)
                || e.StartDate == default)
            {
                _errorMessage = "Company, job title, and start date are required for each position.";
                return;
            }
        }
        _currentStep = 2;
    }

    private void NextFromReferences()
    {
        _errorMessage = null;
        foreach (var r in _references)
        {
            if (string.IsNullOrWhiteSpace(r.Name) || string.IsNullOrWhiteSpace(r.Relationship)
                || string.IsNullOrWhiteSpace(r.Email) || string.IsNullOrWhiteSpace(r.Phone))
            {
                _errorMessage = "All fields are required for each reference.";
                return;
            }
        }
        _currentStep = 3;
    }

    private void NextFromCoverLetter()
    {
        _errorMessage = null;
        if (string.IsNullOrWhiteSpace(_coverLetter))
        {
            _errorMessage = "Please write a cover letter.";
            return;
        }
        _currentStep = 4;
    }

    private void AddWorkEntry() => _workEntries.Add(new());

    private void RemoveWorkEntry(int index)
    {
        if (_workEntries.Count > 1) _workEntries.RemoveAt(index);
    }

    private void AddReference()
    {
        if (_references.Count < 3) _references.Add(new());
    }

    private void RemoveReference(int index)
    {
        if (_references.Count > 2) _references.RemoveAt(index);
    }

    private async Task SubmitApplication()
    {
        _errorMessage = null;
        _loading = true;
        try
        {
            var personal = new PersonalInfo(_fullName, _email, _phone, _address);
            var workHistory = new WorkHistory(
                _workEntries.Select(e => new WorkEntry(
                    e.Company, e.Title, e.StartDate,
                    e.IsCurrent ? null : e.EndDate,
                    e.Description ?? "")).ToList());
            var references = _references
                .Select(r => new Reference(r.Name, r.Relationship, r.Email, r.Phone)).ToList();
            var application = new JobApplication(personal, workHistory, references, _coverLetter);

            _applicationId = await ApplicationService.SubmitApplicationAsync(application);
            _submitted = true;
        }
        catch (Exception ex)
        {
            _errorMessage = $"Submission failed: {ex.Message}";
        }
        finally { _loading = false; }
    }

    // Mutable view-models for form binding
    private class WorkEntryModel
    {
        public string Company { get; set; } = "";
        public string Title { get; set; } = "";
        public DateTime StartDate { get; set; }
        public DateTime? EndDate { get; set; }
        public bool IsCurrent { get; set; }
        public string? Description { get; set; } = "";
    }

    private class ReferenceModel
    {
        public string Name { get; set; } = "";
        public string Relationship { get; set; } = "";
        public string Email { get; set; } = "";
        public string Phone { get; set; } = "";
    }
}

